export class PortraitActor extends ex.Actor {
    public isFront: boolean;
    public rank: number;
    public item: [string, number, string, number];
    private bounceTimer = 0;
    private baseScale: number;
    private isCheering = false;
    private frameSource: ex.ImageSource;
    private regionA: ex.ImageSource;
    private regionB: ex.ImageSource;
    private regionC: ex.ImageSource;

    constructor(
        x: number, y: number, isFront: boolean, rank: number,
        item: [string, number, string, number],
        resources: { frame: ex.ImageSource; audienceRegionA: ex.ImageSource; audienceRegionB: ex.ImageSource; audienceRegionC: ex.ImageSource }
    ) {
        super({
            pos: new ex.Vector(x, y),
            width: 128,
            height: 128,
            anchor: ex.Vector.Half,
            scale: new ex.Vector(isFront ? 1.0 : 0.88, isFront ? 1.0 : 0.88),
            z: isFront ? 3 : 2
        });
        this.isFront = isFront;
        this.rank = rank;
        this.item = item;
        this.baseScale = isFront ? 1.0 : 0.88;
        this.frameSource = resources.frame;
        this.regionA = resources.audienceRegionA;
        this.regionB = resources.audienceRegionB;
        this.regionC = resources.audienceRegionC;
    }

    public onInitialize(engine: ex.Engine) {
        this.loadGraphics();
    }

    private loadGraphics() {
        const [sheetName, index] = this.item;
        let src = this.regionC;
        if (sheetName.includes("region_A")) src = this.regionA;
        else if (sheetName.includes("region_B")) src = this.regionB;

        const cols = 5;
        const spriteW = src.width / cols;
        const spriteH = src.height / cols;
        const colIdx = index % cols;
        const rowIdx = Math.floor(index / cols);

        const sprite = new ex.Sprite({
            image: src,
            sourceView: {
                x: colIdx * spriteW,
                y: rowIdx * spriteH,
                width: spriteW,
                height: spriteH
            },
            destSize: { width: 120, height: 120 }
        });

        const frameGroup = createPortraitFrameGroup(this.frameSource, "audience", this.rank, 128, 128, 24);
        const group = new ex.GraphicsGroup({
            members: [
                { graphic: sprite, offset: new ex.Vector(4, 4) },
                { graphic: frameGroup, offset: new ex.Vector(0, 0) }
            ],
            width: 128,
            height: 128
        });

        this.graphics.use(group, { anchor: ex.Vector.Half });
    }

    public cheer() {
        if (this.isCheering) return;
        this.isCheering = true;
        this.bounceTimer = 0;
    }

    public onPostUpdate(engine: ex.Engine, delta: number) {
        if (this.isCheering) {
            this.bounceTimer += delta / 1000;
            const duration = 0.52;
            if (this.bounceTimer >= duration) {
                this.isCheering = false;
                this.graphics.offset.y = 0;
                this.scale = new ex.Vector(this.baseScale, this.baseScale);
            } else {
                const progress = this.bounceTimer / duration;
                const jumpHeight = 14 * Math.sin(progress * Math.PI);
                const scaleBoost = 0.1 * Math.sin(progress * Math.PI);
                this.graphics.offset.y = -jumpHeight;
                this.scale = new ex.Vector(this.baseScale + scaleBoost, this.baseScale + scaleBoost);
            }
        }
    }
}

export class CompanionActor extends ex.Actor {
    public idx: number;
    public item: [string, number, string, string];
    public role: string;
    private baseX: number;
    private swayTime: number;
    private assistTimer = 0;
    public isAssisting = false;
    private assistStrong = false;
    private frameSource: ex.ImageSource;
    private portraitCoreA: ex.ImageSource;
    private portraitCandA1: ex.ImageSource;
    private portraitCandA2: ex.ImageSource;
    private portraitCandB1: ex.ImageSource;
    private portraitCandB2: ex.ImageSource;

    constructor(
        x: number, y: number, idx: number,
        item: [string, number, string, string],
        resources: {
            frame: ex.ImageSource;
            portraitCoreA: ex.ImageSource;
            portraitCandA1: ex.ImageSource;
            portraitCandA2: ex.ImageSource;
            portraitCandB1: ex.ImageSource;
            portraitCandB2: ex.ImageSource;
        }
    ) {
        super({
            pos: new ex.Vector(x, y),
            width: 140,
            height: 140,
            anchor: ex.Vector.Half,
            z: 10
        });
        this.idx = idx;
        this.item = item;
        this.role = item[3] || "clap";
        this.baseX = x;
        this.swayTime = Math.random() * 5;
        this.frameSource = resources.frame;
        this.portraitCoreA = resources.portraitCoreA;
        this.portraitCandA1 = resources.portraitCandA1;
        this.portraitCandA2 = resources.portraitCandA2;
        this.portraitCandB1 = resources.portraitCandB1;
        this.portraitCandB2 = resources.portraitCandB2;
    }

    public onInitialize(engine: ex.Engine) {
        this.loadGraphics();
    }

    private loadGraphics() {
        const [sheetName, index] = this.item;
        let src = this.portraitCandB2;
        if (sheetName.includes("core_A")) src = this.portraitCoreA;
        else if (sheetName.includes("candidates_A1")) src = this.portraitCandA1;
        else if (sheetName.includes("candidates_A2")) src = this.portraitCandA2;
        else if (sheetName.includes("candidates_B1")) src = this.portraitCandB1;

        const cols = 4;
        const spriteW = src.width / cols;
        const spriteH = src.height / cols;
        const colIdx = index % cols;
        const rowIdx = Math.floor(index / cols);

        const sprite = new ex.Sprite({
            image: src,
            sourceView: {
                x: colIdx * spriteW,
                y: rowIdx * spriteH,
                width: spriteW,
                height: spriteH
            },
            destSize: { width: 132, height: 132 }
        });

        const frameGroup = createPortraitFrameGroup(this.frameSource, "elegant", this.idx, 140, 140, 24);
        const group = new ex.GraphicsGroup({
            members: [
                { graphic: sprite, offset: new ex.Vector(4, 4) },
                { graphic: frameGroup, offset: new ex.Vector(0, 0) }
            ],
            width: 140,
            height: 140
        });

        this.graphics.use(group, { anchor: ex.Vector.Half });
    }

    public triggerAssist(strong = false) {
        this.isAssisting = true;
        this.assistStrong = strong;
        this.assistTimer = 0;
    }

    public onPostUpdate(engine: ex.Engine, delta: number) {
        this.swayTime += delta / 1000;
        
        let targetRot = 0.017 * Math.sin(this.swayTime * 2);
        let targetScale = 1.0;
        let offsetY = 0;

        if (this.isAssisting) {
            this.assistTimer += delta / 1000;
            const duration = this.assistStrong ? 0.98 : 0.62;
            if (this.assistTimer >= duration) {
                this.isAssisting = false;
                this.pos.x = this.baseX;
            } else {
                const progress = this.assistTimer / duration;
                const sinP = Math.sin(progress * Math.PI);
                if (this.role === "strings") {
                    this.pos.x = this.baseX + (this.assistStrong ? 20 : 10) * sinP;
                    targetRot = -0.07 * sinP;
                } else if (this.role === "dancer") {
                    targetRot = 0.25 * sinP;
                    targetScale = 1.0 + 0.08 * sinP;
                } else if (this.role === "mystic") {
                    offsetY = (this.assistStrong ? 20 : 12) * sinP;
                    targetScale = 1.0 + 0.1 * sinP;
                } else if (this.role === "salon") {
                    offsetY = (this.assistStrong ? 12 : 8) * sinP;
                    targetRot = -0.1 * sinP;
                } else {
                    targetScale = 1.0 + 0.12 * sinP;
                }
            }
        }

        this.rotation = targetRot;
        this.scale = new ex.Vector(targetScale, targetScale);
        this.graphics.offset.y = -offsetY;
    }
}

export function pickUnique<T>(pool: T[], count: number): T[] {
    const source = [...pool];
    const picks: T[] = [];
    while (source.length && picks.length < count) {
        const idx = Math.floor(Math.random() * source.length);
        picks.push(source.splice(idx, 1)[0]);
    }
    return picks;
}

export function audienceKey(item: [string, number, string, number]): string {
    return `${item[0]}:${item[1]}`;
}

export function audienceRegion(item: [string, number, string, number]): string {
    const [sheet, index] = item;
    const columns = 5; 
    const row = Math.floor(index / columns);
    return AUDIENCE_REGION_ROWS[sheet]?.[row] || "generic";
}

export function keepAudienceAwayFromUi(p: { x: number; y: number; isFront: boolean }): void {
    const half = p.isFront ? 64 : 56;
    const uiRects = [
        { left: 0, right: 220, top: 0, bottom: 335 }
    ];
    for (const rect of uiRects) {
        const overlapsX = p.x + half > rect.left && p.x - half < rect.right;
        const overlapsY = p.y + half > rect.top && p.y - half < rect.bottom;
        if (overlapsX && overlapsY) {
            p.x = rect.right + half + 10;
        }
    }
}

export function pickStageAudience(stageMeta: { audienceRegion: string } | null, count: number = 22): Array<[string, number, string, number]> {
    const used = new Set<string>();
    const region = stageMeta?.audienceRegion || "generic";
    const localPool = AUDIENCE_POOL.filter(item => audienceRegion(item) === region);
    const genericPool = AUDIENCE_POOL.filter(item => audienceRegion(item) === "generic");
    const otherPool = AUDIENCE_POOL.filter(item => audienceRegion(item) !== region && audienceRegion(item) !== "generic");

    const picks: Array<[string, number, string, number]> = [];
    const localLimit = Math.min(Math.ceil(count * 0.45), localPool.length);
    const localPicks = pickUnique(localPool, localLimit);
    picks.push(...localPicks);
    localPicks.forEach(item => used.add(audienceKey(item)));

    const remainingCount = count - picks.length;
    const filteredGeneric = genericPool.filter(item => !used.has(audienceKey(item)));
    const genericPicks = pickUnique(filteredGeneric, Math.min(remainingCount, filteredGeneric.length));
    picks.push(...genericPicks);
    genericPicks.forEach(item => used.add(audienceKey(item)));

    if (picks.length < count) {
        const nextRemaining = count - picks.length;
        const filteredOther = otherPool.filter(item => !used.has(audienceKey(item)));
        const otherPicks = pickUnique(filteredOther, Math.min(nextRemaining, filteredOther.length));
        picks.push(...otherPicks);
    }
    return picks;
}

export function renderAudienceEx(
    engine: ex.Engine,
    picks: Array<[string, number, string, number]>,
    resources: { frame: ex.ImageSource; audienceRegionA: ex.ImageSource; audienceRegionB: ex.ImageSource; audienceRegionC: ex.ImageSource },
    onCheckLayout: () => void
): PortraitActor[] {
    picks = picks.slice(0, MAX_AUDIENCE_COUNT);
    const audienceGroup: PortraitActor[] = [];

    const total = picks.length;
    if (total === 0) return [];

    const frontGroup: Array<{ item: [string, number, string, number]; originalIdx: number }> = [];
    const backGroup: Array<{ item: [string, number, string, number]; originalIdx: number }> = [];
    picks.forEach((item, idx) => {
        if (idx % 2 === 0) frontGroup.push({ item, originalIdx: idx });
        else backGroup.push({ item, originalIdx: idx });
    });

    const centerX = 960; 
    const angleRange = 3.0; 
    const startAngle = 3 * Math.PI / 2 - angleRange / 2;

    const placements: Array<{
        item: [string, number, string, number];
        originalIdx: number;
        isFront: boolean;
        x: number;
        y: number;
    }> = [];

    const calculateGroupPlacements = (group: typeof frontGroup, isFront: boolean) => {
        const count = group.length;
        if (count === 0) return;

        const centerY = 280; 
        const radiusBaseX = isFront ? 700 : 820;
        const radiusBaseY = isFront ? 110 : 240;
        const staggerOffset = isFront ? 0 : (angleRange / Math.max(1, count)) * 0.5;

        group.forEach((entry, i) => {
            const { item, originalIdx } = entry;
            if (!item) return;

            let angle = 3 * Math.PI / 2;
            if (count > 1) {
                const ratio = i / (count - 1);
                angle = startAngle + ratio * angleRange + staggerOffset;
            } else if (count === 1) {
                angle = 3 * Math.PI / 2 + staggerOffset;
            }

            const angleJitter = (Math.random() - 0.5) * 0.008;
            const radiusJitter = (Math.random() - 0.5) * 8;
            const finalAngle = angle + angleJitter;
            const finalRadiusX = radiusBaseX + radiusJitter;
            const finalRadiusY = radiusBaseY + radiusJitter;

            const x = centerX + finalRadiusX * Math.cos(finalAngle);
            const yOffsetJitter = (Math.random() - 0.5) * (isFront ? 36 : 48);
            
            const angleFromCenter = Math.abs(finalAngle - 3 * Math.PI / 2);
            const edgeDrop = Math.pow(angleFromCenter / (angleRange / 2), 2) * 36;
            const y = centerY + finalRadiusY * Math.sin(finalAngle) + yOffsetJitter + edgeDrop;

            placements.push({
                item,
                originalIdx,
                isFront,
                x,
                y
            });
        });
    };

    calculateGroupPlacements(backGroup, false);
    calculateGroupPlacements(frontGroup, true);

    const compMinX = 960 - 246 - 64;
    const compMaxX = 960 + 246 + 64;
    const compMinY = 316 - 64;
    const compMaxY = 316 + 140 + 64;

    placements.forEach(p => {
        if (p.x > compMinX && p.x < compMaxX) {
            if (p.y > compMinY && p.y < compMaxY) {
                p.y = compMinY - 4; 
            }
        }
        keepAudienceAwayFromUi(p);
    });

    for (let iter = 0; iter < 10; iter++) {
        for (let i = 0; i < placements.length; i++) {
            for (let j = i + 1; j < placements.length; j++) {
                const p1 = placements[i];
                const p2 = placements[j];
                const dx = p2.x - p1.x;
                const dy = p2.y - p1.y;
                const dist = Math.hypot(dx, dy);
                const minDist = p1.isFront === p2.isFront ? 112 : 98;
                if (dist < minDist && dist > 0) {
                    const overlap = minDist - dist;
                    const forceX = (dx / dist) * overlap * 0.5;
                    const forceY = (dy / dist) * overlap * 0.5;
                    p1.x -= forceX;
                    p1.y -= forceY;
                    p2.x += forceX;
                    p2.y += forceY;
                }
            }
        }

        placements.forEach(p => {
            keepAudienceAwayFromUi(p);
            if (p.y > 462) p.y = 462;
            if (p.y < 64) p.y = 64;
            if (p.x < 64) p.x = 64;
            if (p.x > 1856) p.x = 1856;
        });
    }

    placements.forEach(p => {
        const actor = new PortraitActor(p.x, p.y, p.isFront, (p.originalIdx % 3) + 1, p.item, resources);
        engine.add(actor);
        audienceGroup.push(actor);
    });

    window.setTimeout(onCheckLayout, 60);
    return audienceGroup;
}

export function updateCompanionsEx(
    engine: ex.Engine,
    companions: Array<[string, number, string, string]>,
    resources: {
        frame: ex.ImageSource;
        portraitCoreA: ex.ImageSource;
        portraitCandA1: ex.ImageSource;
        portraitCandA2: ex.ImageSource;
        portraitCandB1: ex.ImageSource;
        portraitCandB2: ex.ImageSource;
    },
    count: number
): CompanionActor[] {
    const companionGroup: CompanionActor[] = [];
    const startX = 960 - ((count - 1) * 88); 
    const centerY = 350 + 70;

    for (let i = 0; i < count; i++) {
        if (!companions[i]) continue;
        const x = startX + i * 176;
        const actor = new CompanionActor(x, centerY, i + 2, companions[i], resources); 
        engine.add(actor);
        companionGroup.push(actor);
    }
    return companionGroup;
}
