import { ATTR, TARGET_FRAME_MS, MAX_VIZ_PARTICLES } from './types';
import { appendSparkParticles, appendCompanionParticles, VisualizerParticle } from './rhythm-test-particles';

export class RhythmVisualizer {
    private canvas: HTMLCanvasElement;
    private ctx: CanvasRenderingContext2D;
    private visualizerAnimId = 0;
    private lastVisualizerDraw = 0;

    public vizBeams = { brave: 0, elegant: 0, mystic: 0 } as Record<string, number>;
    public vizParticles: VisualizerParticle[] = [];

    // 状態を外部から取得するためのコールバック
    private getActiveState: () => string;

    constructor(
        canvas: HTMLCanvasElement,
        getActiveState: () => string
    ) {
        this.canvas = canvas;
        const context = canvas.getContext("2d");
        if (!context) throw new Error("Could not get 2D context");
        this.ctx = context;
        this.getActiveState = getActiveState;
    }

    public start(): void {
        this.stop();
        const draw = (now: number) => {
            if (now - this.lastVisualizerDraw >= TARGET_FRAME_MS) {
                this.lastVisualizerDraw = now;
                this.draw();
            }
            this.visualizerAnimId = requestAnimationFrame(draw);
        };
        this.visualizerAnimId = requestAnimationFrame(draw);
    }

    public stop(): void {
        cancelAnimationFrame(this.visualizerAnimId);
    }

    public emitParticles(x: number, y: number, color: string, type: "spark" | "companion", char = "", strong = false): void {
        if (type === "spark") {
            appendSparkParticles(this.vizParticles, x, y, color);
        } else if (type === "companion") {
            appendCompanionParticles(this.vizParticles, x, y, color, char, strong);
        }
        if (this.vizParticles.length > MAX_VIZ_PARTICLES) {
            this.vizParticles.splice(0, this.vizParticles.length - MAX_VIZ_PARTICLES);
        }
    }

    public addBubbleParticle(particle: VisualizerParticle): void {
        this.vizParticles.push(particle);
    }

    private draw(): void {
        const ctx = this.ctx;
        const w = this.canvas.width;
        const h = this.canvas.height;
        ctx.clearRect(0, 0, w, h);

        const activeState = this.getActiveState();
        const singing = activeState === "VOCAL" || activeState === "VOCAL_UP";
        const amp = singing ? 82 : 34;
        const t = performance.now() * 0.001;

        // サイン波ライン (ビジュアライザーライン)
        ["#a855f7", "#06b6d4", "#ef4444"].forEach((color, idx) => {
            ctx.beginPath();
            ctx.strokeStyle = color;
            ctx.globalAlpha = singing ? 0.48 - idx * 0.08 : 0.18;
            ctx.lineWidth = singing ? 6.5 - idx * 1.0 : 3; // 通常時2->3、歌唱時4->6.5に太く変更
            const step = 18;
            for (let x = 0; x <= w; x += step) {
                const y = h * 0.40 // 仲間たちの高さに合わせて画面中央から10%上（h * 0.40）に変更
                    + Math.sin(x * 0.007 + t * (2.2 + idx * 0.3)) * amp * Math.sin((x / w) * Math.PI)
                    + Math.sin(x * 0.021 - t * 1.4 + idx) * amp * 0.22;
                if (x === 0) ctx.moveTo(x, y);
                else ctx.lineTo(x, y);
            }
            ctx.stroke();
        });
        ctx.globalAlpha = 1;

        // オーラエフェクト
        for (const attr of Object.keys(this.vizBeams)) {
            if (this.vizBeams[attr] <= 0) continue;
            this.vizBeams[attr] -= 0.045;
            ctx.save();
            ctx.beginPath();
            const radiusX = 480;
            const radiusY = 130;
            ctx.translate(w / 2, h * 0.75);
            ctx.scale(1, radiusY / radiusX);
            const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, radiusX);
            const color = ATTR[attr].color;
            const opacity = this.vizBeams[attr] * 0.22;
            grad.addColorStop(0, this.hexToRgb(color, opacity));
            grad.addColorStop(0.5, this.hexToRgb(color, opacity * 0.45));
            grad.addColorStop(1, this.hexToRgb(color, 0));
            ctx.fillStyle = grad;
            ctx.arc(0, 0, radiusX, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        // 歌唱時の上昇バブルパーティクル
        if (singing && Math.random() < 0.05) {
            this.vizParticles.push({
                x: w * (0.28 + Math.random() * 0.52),
                y: h * (0.32 + Math.random() * 0.32),
                type: "bubble",
                vx: 0,
                vy: -0.9 - Math.random() * 1.7,
                alpha: 1,
                decay: 0.012,
                size: 3 + Math.random() * 5,
                color: ["#a855f7", "#06b6d4", "#ef4444", "#fbbf24"][Math.floor(Math.random() * 4)]
            });
        }

        // パーティクルの更新と描画
        this.vizParticles = this.vizParticles.filter(p => {
            p.alpha -= p.decay;
            if (p.alpha <= 0) return false;

            if (p.type === "ring") {
                const currentSize = p.size + ((p.targetSize || 80) - p.size) * (1 - p.alpha);
                ctx.save();
                ctx.globalAlpha = p.alpha;
                ctx.strokeStyle = p.color;
                ctx.lineWidth = 3;
                ctx.beginPath();
                ctx.arc(p.x, p.y, currentSize, 0, Math.PI * 2);
                ctx.stroke();
                ctx.restore();
            } else if (p.type === "bubble") {
                if (p.vy) p.y += p.vy;
                ctx.save();
                ctx.globalAlpha = p.alpha;
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            } else if (p.type === "text") {
                if (p.vx) p.x += p.vx * 0.016;
                if (p.vy) p.y += p.vy * 0.016;
                if (p.rot !== undefined && p.vrot !== undefined) p.rot += p.vrot;
                ctx.save();
                ctx.globalAlpha = p.alpha;
                ctx.fillStyle = p.color;
                ctx.font = `bold ${p.size}px Outfit, sans-serif`;
                ctx.textAlign = "center";
                ctx.textBaseline = "middle";
                ctx.translate(p.x, p.y);
                if (p.rot !== undefined) ctx.rotate(p.rot * Math.PI / 180);
                ctx.fillText(p.char || "", 0, 0);
                ctx.restore();
            }
            return true;
        });
    }

    private hexToRgb(hex: string, alpha: number): string {
        const n = parseInt(hex.slice(1), 16);
        return `rgba(${(n >> 16) & 255}, ${(n >> 8) & 255}, ${n & 255}, ${alpha})`;
    }
}
