import { Note, ATTR, JUDGMENT_X_RATIO, NOTE_SPAWN_X_RATIO, LATE_MISS_MARGIN_SEC, COUNTDOWN_SEC, APPROACH_SEC, TARGET_FRAME_MS } from './types';

export interface RhythmCoreCallbacks {
    getOffset: () => number;
    getWindowSec: () => number;
    getNoteSpeed: () => number;
    getBgmVolume: () => number;
    getAudioDuration: () => number;
    isAudioEnded: () => boolean;
    isAudioPaused: () => boolean;
    getAudioTime: () => number;
    playAudio: () => Promise<void>;
    pauseAudio: () => void;
    setAudioTime: (time: number) => void;
    setAudioMuted: (muted: boolean) => void;
    setAudioVolume: (vol: number) => void;
    
    // UI通知
    updateHUD: (stats: { score: number; combo: number; gameTime: number; accuracy: string }) => void;
    updateJudgeMeter: (level: number, color: string, text: string, upgradeInfo?: { originalText: string; isUpgrade: boolean }) => void;
    showHitText: (text: string, color: string, y: number) => void;
    burstAt: (x: number, y: number, color: string, combo: number) => void;
    showTiming: (diff: number, windowSec: number, color: string) => void;
    
    // エフェクト・モジュール連携
    emitVisualizerParticles: (x: number, y: number, color: string, type: "spark" | "companion", char?: string, strong?: boolean) => void;
    triggerCompanionAssist: (strong: boolean) => void;
    adjustAudienceHeat: (delta: number) => void;
    onGameEnd: (results: { score: number; maxCombo: number; perfects: number; greats: number; goods: number; misses: number; scoreVal: number }) => void;
    onCountdownState: (text: string, phase: 'active' | 'approach' | 'inactive') => void;
}

export interface RhythmCoreOptions {
    showReleaseInputEffects?: boolean;
}

export class RhythmGameCore {
    public isPlaying = false;
    public isPaused = false;
    public isCountingDown = false;
    public isApproaching = false;

    public score = 0;
    public combo = 0;
    public maxCombo = 0;
    public perfects = 0;
    public greats = 0;
    public goods = 0;
    public misses = 0;

    public gameTime = 0;
    public currentNotes: Note[] = [];

    private countdownStart = 0;
    private approachStart = 0;
    private songStartPerformance = 0;
    private lastGameLoopUpdate = 0;
    private loopId = 0;

    private callbacks: RhythmCoreCallbacks;
    private showReleaseInputEffects: boolean;

    constructor(callbacks: RhythmCoreCallbacks, options: RhythmCoreOptions = {}) {
        this.callbacks = callbacks;
        this.showReleaseInputEffects = options.showReleaseInputEffects ?? true;
    }

    public getAdjustedGameTime(): number {
        return this.gameTime - this.callbacks.getOffset() / 1000;
    }

    public resetRunStats(): void {
        this.score = 0;
        this.combo = 0;
        this.maxCombo = 0;
        this.perfects = 0;
        this.greats = 0;
        this.goods = 0;
        this.misses = 0;
        this.gameTime = 0;
        this.callbacks.adjustAudienceHeat(0);
        this.callbacks.updateJudgeMeter(0, "#94a3b8", "準備完了");
        this.callbacks.showTiming(0, 0.150, "#94a3b8"); // 暫定リセット
    }

    public updateHUD(): void {
        const judged = this.perfects + this.greats + this.goods + this.misses;
        const weighted = this.perfects + this.greats * 0.72 + this.goods * 0.42;
        const accuracy = judged ? `${Math.round((weighted / judged) * 100)}%` : "--";
        this.callbacks.updateHUD({
            score: this.score,
            combo: this.combo,
            gameTime: this.gameTime,
            accuracy
        });
    }

    public laneY(attr: string, containerHeight: number): number {
        const yRatio = ATTR[attr] ? ATTR[attr].y : 0.50;
        return containerHeight * yRatio;
    }

    public judgeInput(attribute: string, isRelease = false, containerWidth: number, containerHeight: number, activeState: string): void {
        if (!this.isPlaying || this.isPaused || this.isCountingDown || this.gameTime < 0) return;

        const now = this.getAdjustedGameTime();
        const windowSec = this.callbacks.getWindowSec();
        let closest: Note | null = null;
        let closestDiff = Infinity;

        for (const note of this.currentNotes) {
            if (note.missed || note.attribute !== attribute) continue;
            if (isRelease && note.released) continue;
            if (!isRelease && note.hit) continue;

            const abs = Math.abs(note.time - now);
            if (abs <= windowSec && abs < closestDiff) {
                closest = note;
                closestDiff = abs;
            }
        }

        if (!closest) {
            if (!isRelease) {
                this.callbacks.updateJudgeMeter(1, "#64748b", "空振り");
            }
            return;
        }

        const ratio = closestDiff / windowSec;
        let text = "グッド";
        let points = 25;
        let color = "#38bdf8";
        let level = 2;
        if (ratio <= 0.28) {
            text = "パーフェクト";
            points = 100;
            color = "#fbbf24";
            level = 4;
        } else if (ratio <= 0.62) {
            text = "グレート";
            points = 60;
            color = "#34d399";
            level = 3;
        }

        const originalText = closest.text || "";
        let isUpgrade = false;

        if (!isRelease) {
            closest.hit = true;
            closest.level = level;
            closest.points = points;
            closest.text = text;
            closest.color = color;
            if (level === 4) closest.released = true;
            if (closest.dom) closest.dom.remove();

            if (level === 4) this.perfects++;
            else if (level === 3) this.greats++;
            else this.goods++;

            this.score += points + Math.min(this.combo, 80);
            this.combo++;
            this.maxCombo = Math.max(this.maxCombo, this.combo);
        } else {
            closest.released = true;
            if (!closest.hit) {
                closest.hit = true;
                closest.level = level;
                closest.points = points;
                closest.text = text;
                closest.color = color;
                if (closest.dom) closest.dom.remove();

                if (level === 4) this.perfects++;
                else if (level === 3) this.greats++;
                else this.goods++;

                this.score += points + Math.min(this.combo, 80);
                this.combo++;
                this.maxCombo = Math.max(this.maxCombo, this.combo);
            } 
            else if (level > (closest.level || 0)) {
                isUpgrade = true;
                if (closest.level === 3) this.greats--;
                else if (closest.level === 2) this.goods--;

                if (level === 4) this.perfects++;
                else if (level === 3) this.greats++;

                this.score += (points - (closest.points || 0));
                closest.level = level;
                closest.points = points;
                closest.text = text;
                closest.color = color;
            } else {
                level = closest.level || level;
                points = closest.points || points;
                text = closest.text || text;
                color = closest.color || color;
            }
        }

        const isDetermined = (isRelease || level === 4);
        const shouldShowInputEffects = !isRelease || this.showReleaseInputEffects;

        if (isDetermined) {
            const y = this.laneY(attribute, containerHeight);
            if (shouldShowInputEffects) {
                this.callbacks.adjustAudienceHeat(level === 4 ? 5 : (level === 3 ? 3 : 1));
                this.callbacks.showHitText(text, color, y);

                if (level >= 3) {
                    const x = containerWidth * JUDGMENT_X_RATIO;
                    this.callbacks.burstAt(x, y, color, this.combo);
                }
            }

            const timingText = `${text} ${Math.round((closest.time - now) * 1000)}ms`;
            if (isRelease) {
                this.callbacks.updateJudgeMeter(level, color, timingText, { originalText, isUpgrade });
            } else {
                this.callbacks.updateJudgeMeter(level, color, timingText);
            }
        }

        if (!isRelease || this.showReleaseInputEffects) {
            const x = containerWidth * JUDGMENT_X_RATIO;
            const y = this.laneY(attribute, containerHeight);
            this.callbacks.emitVisualizerParticles(x, y, color, "spark");
            this.callbacks.triggerCompanionAssist(activeState === "VOCAL_UP" || text === "パーフェクト");
            this.callbacks.showTiming(closest.time - now, windowSec, color);
        }
        this.updateHUD();
    }

    public missNote(note: Note, containerHeight: number): void {
        note.missed = true;
        this.combo = 0;
        this.misses++;
        this.callbacks.adjustAudienceHeat(-8);
        if (note.dom) note.dom.remove();
        const y = this.laneY(note.attribute, containerHeight);
        this.callbacks.showHitText("ミス", "#f87171", y);
        this.callbacks.updateJudgeMeter(1, "#f87171", "ミス");
        this.updateHUD();
    }

    public updateNotes(containerWidth: number, containerHeight: number): void {
        const judgmentX = containerWidth * JUDGMENT_X_RATIO;
        const spawnX = containerWidth * NOTE_SPAWN_X_RATIO;
        const noteSpeed = this.callbacks.getNoteSpeed();
        const travelTime = Math.max(0.1, (judgmentX - spawnX) / noteSpeed);
        
        for (const note of this.currentNotes) {
            if (note.hit || note.missed) continue;
            if (note.time <= this.gameTime + travelTime) {
                if (!note.dom) {
                    const el = document.createElement("div");
                    el.className = `note ${note.attribute}`;
                    el.style.top = `${ATTR[note.attribute].y * 100}%`;
                    const iconPos = {
                        brave: "0% 42.857%",
                        elegant: "14.285% 42.857%",
                        mystic: "28.571% 42.857%"
                    } as Record<string, string>;
                    el.innerHTML = `<span class="note-icon" style="background-position:${iconPos[note.attribute]}"></span>`;
                    
                    const layer = document.getElementById("notes-layer");
                    if (layer) layer.appendChild(el);
                    note.dom = el;
                }
                const delta = note.time - this.gameTime;
                const x = judgmentX - delta * noteSpeed;
                note.dom.style.transform = `translate3d(${x}px, 0, 0)`;
                
                if (!note.pulseTriggered && Math.abs(delta) < 0.04) {
                    note.pulseTriggered = true;
                    const icon = document.querySelector(`.judgment-icon.${note.attribute}`);
                    if (icon) {
                        icon.classList.add("shrink");
                        setTimeout(() => icon.classList.remove("shrink"), 100);
                    }
                }
            }
            if (this.gameTime >= 0 && this.gameTime - note.time > LATE_MISS_MARGIN_SEC && !note.hit) {
                this.missNote(note, containerHeight);
            }
        }
    }

    public getTrackEndTime(): number {
        const lastNoteTime = this.currentNotes.length ? this.currentNotes[this.currentNotes.length - 1].time : 0;
        const audioDuration = this.callbacks.getAudioDuration();
        if (Number.isFinite(audioDuration) && audioDuration > 0) {
            return audioDuration + 2.0; // RESULT_GRACE_SEC
        }
        return lastNoteTime + 2.0 + 1.0;
    }

    public startGame(notes: Array<{ time: number; attribute: string }>): void {
        this.resetRunStats();
        
        this.currentNotes = notes.map((note, idx) => ({
            id: idx,
            time: Number(note.time),
            attribute: ATTR[note.attribute] ? note.attribute : "elegant",
            hit: false,
            missed: false,
            dom: null
        })).sort((a, b) => a.time - b.time);
        
        this.isPlaying = true;
        this.isPaused = false;
        this.isCountingDown = true;
        this.isApproaching = false;
        this.countdownStart = performance.now();
        this.lastGameLoopUpdate = 0;
        
        this.callbacks.pauseAudio();
        this.callbacks.setAudioTime(0);
        this.callbacks.setAudioMuted(true);
        this.callbacks.playAudio().catch(() => {});
        
        this.callbacks.onCountdownState("3", "active");
        
        this.loopId = requestAnimationFrame((now) => this.updateGameLoop(now));
    }

    public stopGame(): void {
        this.isPlaying = false;
        this.isPaused = false;
        this.isCountingDown = false;
        this.isApproaching = false;
        cancelAnimationFrame(this.loopId);
        
        this.callbacks.pauseAudio();
        this.callbacks.setAudioMuted(false);
        this.callbacks.setAudioVolume(this.callbacks.getBgmVolume() / 100);
        
        const layer = document.getElementById("notes-layer");
        if (layer) layer.innerHTML = "";
        
        this.callbacks.onCountdownState("", "inactive");
        this.updateHUD();
    }

    public pauseGame(): void {
        if (!this.isPlaying || this.isPaused || this.isCountingDown || this.isApproaching) return;
        this.isPaused = true;
        this.callbacks.pauseAudio();
    }

    public resumeGame(): void {
        if (!this.isPlaying || !this.isPaused) return;
        this.isPaused = false;
        this.songStartPerformance = performance.now() - (this.gameTime * 1000);
        this.callbacks.playAudio().catch(() => {});
    }

    private updateGameLoop(now: number): void {
        if (!this.isPlaying || this.isPaused) return;
        if (now - this.lastGameLoopUpdate < TARGET_FRAME_MS) {
            this.loopId = requestAnimationFrame((n) => this.updateGameLoop(n));
            return;
        }
        this.lastGameLoopUpdate = now;
        
        if (this.isCountingDown) {
            const elapsed = (now - this.countdownStart) / 1000;
            const left = COUNTDOWN_SEC - elapsed;
            this.gameTime = -left - APPROACH_SEC;
            
            if (left > 2.0) this.callbacks.onCountdownState("3", "active");
            else if (left > 1.0) this.callbacks.onCountdownState("2", "active");
            else if (left > 0) this.callbacks.onCountdownState("1", "active");
            else {
                this.isCountingDown = false;
                this.isApproaching = true;
                this.approachStart = performance.now();
                this.callbacks.onCountdownState("GET READY", "approach");
            }
        } else if (this.isApproaching) {
            const elapsed = (performance.now() - this.approachStart) / 1000;
            this.gameTime = elapsed - APPROACH_SEC;
            this.callbacks.onCountdownState("GET READY", "approach");
            if (elapsed >= APPROACH_SEC) {
                this.isApproaching = false;
                this.callbacks.onCountdownState("", "inactive");
                this.songStartPerformance = performance.now();
                this.callbacks.setAudioTime(0);
                this.callbacks.setAudioMuted(false);
                this.callbacks.setAudioVolume(this.callbacks.getBgmVolume() / 100);
                this.callbacks.playAudio().catch(() => {});
            }
        } else {
            const virtualTime = (performance.now() - this.songStartPerformance) / 1000;
            this.gameTime = this.callbacks.isAudioPaused() ? virtualTime : this.callbacks.getAudioTime();
        }

        const laneContainer = document.getElementById("lane-container");
        if (laneContainer) {
            this.updateNotes(laneContainer.clientWidth, laneContainer.clientHeight);
        }
        this.updateHUD();

        if (this.callbacks.isAudioEnded() || this.gameTime >= this.getTrackEndTime()) {
            setTimeout(() => {
                if (this.isPlaying) {
                    this.isPlaying = false;
                    this.callbacks.onGameEnd({
                        score: this.score,
                        maxCombo: this.maxCombo,
                        perfects: this.perfects,
                        greats: this.greats,
                        goods: this.goods,
                        misses: this.misses,
                        scoreVal: this.score
                    });
                }
            }, 650);
            return;
        }
        this.loopId = requestAnimationFrame((n) => this.updateGameLoop(n));
    }
}
